import React, { useState } from 'react';
import HighchartsReact from 'highcharts-react-official';
import Highcharts from 'highcharts';
import { buildChartConfig, buildBarConfig, buildLineConfig, buildPieConfig } from '../utils/chartUtils';
import DataTable from './DataTable';
import './ChatMessage.css';

const CHART_ICONS = {
  bar:   '▬',
  line:  '〰',
  pie:   '◉',
  table: '⊞',
};

export default function ChatMessage({ message }) {
  const { role, text, queryResult } = message;
  const [activeChart, setActiveChart] = useState(message.chartType || 'bar');
  const [showCode, setShowCode]       = useState(false);

  const isUser      = role === 'user';
  const isError     = role === 'error';
  const hasData     = queryResult && Array.isArray(queryResult.data) && queryResult.data.length > 0;
  const isScalar    = queryResult && !Array.isArray(queryResult.data);

  const chartConfig = hasData && activeChart !== 'table'
    ? buildChartConfig(activeChart, queryResult.data, queryResult.question || '')
    : null;

  return (
    <div className={`message-wrapper ${role}`} style={{ animation: 'fadeSlideIn 0.3s ease forwards' }}>
      {/* Avatar */}
      <div className={`message-avatar ${role}`}>
        {isUser ? '◈' : isError ? '⚠' : '✦'}
      </div>

      <div className="message-body">
        {/* Role label */}
        <span className="message-role">
          {isUser ? 'YOU' : isError ? 'ERROR' : 'FLIGHTIQ'}
        </span>

        {/* Text bubble */}
        <div className={`message-bubble ${role}`}>
          <p className="message-text">{text}</p>

          {/* Scalar result */}
          {isScalar && queryResult.data !== null && (
            <div className="scalar-result">
              <span className="scalar-label">RESULT</span>
              <span className="scalar-value">{String(queryResult.data)}</span>
            </div>
          )}
        </div>

        {/* Data panel */}
        {hasData && (
          <div className="data-panel">
            {/* Panel header */}
            <div className="panel-header">
              <div className="panel-meta">
                <span className="panel-badge">
                  {queryResult.row_count} ROWS
                </span>
                {queryResult.columns && (
                  <span className="panel-badge secondary">
                    {queryResult.columns.length} COLS
                  </span>
                )}
              </div>

              {/* Chart type switcher */}
              <div className="chart-switcher">
                {Object.entries(CHART_ICONS).map(([type, icon]) => (
                  <button
                    key={type}
                    className={`chart-btn ${activeChart === type ? 'active' : ''}`}
                    onClick={() => setActiveChart(type)}
                    title={type.toUpperCase()}
                  >
                    <span className="chart-btn-icon">{icon}</span>
                    <span className="chart-btn-label">{type}</span>
                  </button>
                ))}
              </div>

              {/* Code toggle */}
              <button
                className={`code-toggle ${showCode ? 'active' : ''}`}
                onClick={() => setShowCode(v => !v)}
              >
                {'</>'} {showCode ? 'HIDE' : 'QUERY'}
              </button>
            </div>

            {/* Generated code */}
            {showCode && (
              <div className="code-block">
                <pre>{queryResult.generated_code}</pre>
              </div>
            )}

            {/* Chart or table */}
            <div className="chart-area">
              {activeChart === 'table' || !chartConfig ? (
                <DataTable data={queryResult.data} columns={queryResult.columns} />
              ) : (
                <HighchartsReact
                  highcharts={Highcharts}
                  options={chartConfig}
                  containerProps={{ style: { width: '100%', height: '340px' } }}
                />
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
